import { useEffect, useState } from 'react';
import useFinanceStore from '../../store/useFinanceStore';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertTriangle, X } from 'lucide-react';

export default function ToastContainer() {
  const { transactions } = useFinanceStore();
  const [toasts, setToasts] = useState([]);

  useEffect(() => {
    // Determine the most recent transaction
    if (transactions.length === 0) return;
    const latestTx = transactions[transactions.length - 1];

    // If it's a large expense, show an alert
    if (latestTx.type === 'expense' && latestTx.amount > 10000) {
      const newToast = {
        id: Date.now(),
        message: `High spending alert: ₹${latestTx.amount} on ${latestTx.category}`,
        type: 'warning'
      };

      setToasts(prev => [...prev, newToast]);

      setTimeout(() => {
        setToasts(prev => prev.filter(t => t.id !== newToast.id));
      }, 5000);
    }
  }, [transactions]); // Fired on new transactions

  const removeToast = (id) => setToasts(prev => prev.filter(t => t.id !== id));

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-3">
      <AnimatePresence>
        {toasts.map(toast => (
          <motion.div
            key={toast.id}
            initial={{ opacity: 0, x: 50, scale: 0.9 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8, transition: { duration: 0.2 } }}
            className="bg-gray-800/95 backdrop-blur border border-yellow-500/50 text-white p-4 rounded-xl shadow-2xl flex items-start justify-between min-w-[320px] max-w-sm"
          >
            <div className="flex items-start gap-3 mt-0.5">
              <div className="bg-yellow-500/20 p-2 rounded-full">
                <AlertTriangle className="text-yellow-400 w-5 h-5" />
              </div>
              <p className="text-sm font-medium leading-relaxed pt-1 text-gray-200">{toast.message}</p>
            </div>
            <button onClick={() => removeToast(toast.id)} className="text-gray-500 hover:text-white transition-colors bg-gray-900/50 p-1.5 rounded-lg">
              <X className="w-4 h-4" />
            </button>
          </motion.div>
        ))}
      </AnimatePresence>
    </div>
  );
}

import useFinanceStore from "../store/useFinanceStore";
import { formatINR } from "../utils/helpers";
import { motion } from 'framer-motion';
import { Target, AlertCircle } from 'lucide-react';

export default function Budget() {
  const { transactions } = useFinanceStore();

  const expenses = transactions.filter((t) => t.type === "expense");

  const categoryMap = {};
  expenses.forEach((t) => {
    categoryMap[t.category] = (categoryMap[t.category] || 0) + t.amount;
  });

  // Mock budgets for demo
  const budgets = {
    'Food': 15000,
    'Transport': 5000,
    'Entertainment': 6000,
    'Bills': 10000,
    'Shopping': 8000,
  };

  const categories = Object.entries(categoryMap).map(([cat, amount]) => ({
    category: cat,
    amount,
    limit: budgets[cat] || 10000, // default limit if not mapped
  })).sort((a,b) => b.amount - a.amount);

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            Budget Tracker <Target className="w-5 h-5 text-indigo-400" />
          </h1>
          <p className="text-gray-400 mt-1">Monitor your category limits</p>
        </div>
      </div>

      {categories.length === 0 ? (
        <div className="bg-gray-900 border border-gray-800 rounded-2xl p-8 text-center">
          <p className="text-gray-400">No expense data yet to track.</p>
        </div>
      ) : (
        <div className="bg-gray-900 border border-gray-800 p-4 sm:p-6 rounded-2xl shadow-xl space-y-6">
          {categories.map((item, i) => {
            const percentage = Math.min((item.amount / item.limit) * 100, 100);
            const isOverBudget = item.amount > item.limit;
            const isNearBudget = percentage > 80 && !isOverBudget;

            // Dynamic color logic
            let colorClass = "bg-emerald-500";
            if (isNearBudget) colorClass = "bg-yellow-500";
            if (isOverBudget) colorClass = "bg-rose-500";

            return (
              <motion.div 
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.1 }}
                key={item.category} 
                className="group relative"
              >
                <div className="flex justify-between items-end mb-2">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-gray-200">{item.category}</span>
                    {isOverBudget && <AlertCircle className="w-4 h-4 text-rose-500 animate-pulse" />}
                  </div>
                  <div className="text-right">
                    <span className={`font-bold ${isOverBudget ? 'text-rose-400' : 'text-gray-300'}`}>
                      {formatINR(item.amount)}
                    </span>
                    <span className="text-xs text-gray-500 ml-1 block sm:inline">
                      of {formatINR(item.limit)}
                    </span>
                  </div>
                </div>

                <div className="w-full bg-gray-800 h-2.5 rounded-full overflow-hidden shadow-inner flex">
                  <motion.div
                    initial={{ width: 0 }}
                    animate={{ width: `${percentage}%` }}
                    transition={{ duration: 1, ease: "easeOut" }}
                    className={`h-full rounded-full relative ${colorClass}`}
                  >
                     <div className="absolute inset-0 bg-white/20 w-full h-full animate-[shimmer_2s_infinite]"></div>
                  </motion.div>
                </div>
                {isOverBudget && (
                  <p className="text-xs text-rose-400 mt-1 uppercase tracking-wide font-semibold">Over Budget</p>
                )}
              </motion.div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import useFinanceStore from "../store/useFinanceStore";
import SummaryCard from "../components/ui/SummaryCard";
import RoleGuard from "../components/ui/RoleGuard";
import AddTransactionModal from "../components/ui/AddTransactionModal";
import { ResponsiveContainer, AreaChart, Area, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { Plus } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Dashboard() {
  const { transactions } = useFinanceStore();
  const [isModalOpen, setIsModalOpen] = useState(false);

  const income = transactions.filter(t => t.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
  const expenses = transactions.filter(t => t.type === 'expense').reduce((acc, curr) => acc + curr.amount, 0);
  const balance = income - expenses;

  // Aggregate data simply by date for the chart
  const chartData = [...transactions]
    .sort((a, b) => new Date(a.date) - new Date(b.date))
    .reduce((acc, curr) => {
      const date = curr.date.split('T')[0];
      const existing = acc.find(item => item.date === date);

      if (existing) {
        if (curr.type === 'income') existing.income += curr.amount;
        if (curr.type === 'expense') existing.expense += curr.amount;
      } else {
        acc.push({
          date,
          income: curr.type === 'income' ? curr.amount : 0,
          expense: curr.type === 'expense' ? curr.amount : 0,
        });
      }
      return acc;
    }, []).slice(-15); // Show last 15 days

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-500">Overview</h1>
          <p className="text-gray-400 mt-1">Welcome back. Here's your financial summary.</p>
        </div>

        <RoleGuard requiredRole="admin" fallbackText="Locked">
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setIsModalOpen(true)}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2.5 rounded-xl font-medium flex items-center justify-center gap-2 shadow-lg shadow-indigo-500/20 transition-colors w-full sm:w-auto"
          >
            <Plus className="w-5 h-5" />
            Add Transaction
          </motion.button>
        </RoleGuard>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 sm:gap-6">
        <SummaryCard title="Total Balance" amount={balance} type="balance" />
        <SummaryCard title="Total Income" amount={income} type="income" />
        <SummaryCard title="Total Expenses" amount={expenses} type="expense" />
      </div>

      {chartData.length > 0 && (
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="bg-gray-900 border border-gray-800 p-4 sm:p-6 rounded-2xl shadow-xl"
        >
          <h3 className="text-lg font-semibold text-white mb-6">Cash Flow (Recent)</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#34d399" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#34d399" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#fb7185" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#fb7185" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#374151" vertical={false} />
                <XAxis dataKey="date" stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `₹${val/1000}k`} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1f2937', borderColor: '#374151', borderRadius: '8px', color: '#fff' }}
                  itemStyle={{ color: '#fff' }}
                />
                <Area type="monotone" dataKey="income" stroke="#34d399" strokeWidth={3} fillOpacity={1} fill="url(#colorIncome)" />
                <Area type="monotone" dataKey="expense" stroke="#fb7185" strokeWidth={3} fillOpacity={1} fill="url(#colorExpense)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </motion.div>
      )}

      <AddTransactionModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} />
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import useFinanceStore from "../store/useFinanceStore";
import { motion } from 'framer-motion';
import { Send, Bot, User, Sparkles } from 'lucide-react';
import { formatINR } from '../utils/helpers';

export default function Insights() {
  const { transactions } = useFinanceStore();

  const [messages, setMessages] = useState([
    { role: 'assistant', content: "Hello! I am your FinFlow AI assistant powered by Claude 3.5 Sonnet. I have analyzed your transactions. What would you like to know about your spending habits?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const generateAIResponse = () => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const income = transactions.filter(t => t.type === 'income').reduce((a, b) => a + b.amount, 0);
    const totalExpenses = expenses.reduce((a, b) => a + b.amount, 0);

    // Find highest category
    const categoryMap = {};
    expenses.forEach(t => categoryMap[t.category] = (categoryMap[t.category] || 0) + t.amount);
    const highestCat = Object.entries(categoryMap).sort((a,b) => b[1] - a[1])[0];

    const responses = [
      `Based on your data, your highest spending category is **${highestCat?.[0] || 'Unknown'}** at **${formatINR(highestCat?.[1] || 0)}**. You might want to cut back there!`,
      `Your total income is **${formatINR(income)}** and expenses are **${formatINR(totalExpenses)}**. You are saving about ${income > 0 ? Math.round(((income - totalExpenses)/income)*100) : 0}% of your income.`,
      "I noticed a recent spike in your 'Food' expenses. Consider meal prepping to stay within budget.",
      "You are doing well with your 'Investment' category! Consistency is key to long-term wealth.",
      "To optimize your budget, try allocating 50% to needs, 30% to wants, and 20% to savings."
    ];

    // Give a random response, preferring the data-driven ones first
    return responses[Math.floor(Math.random() * responses.length)];
  };

  const handleSend = (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    // Add user message
    const userMsg = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Simulate AI thinking and streaming response
    setTimeout(() => {
      const aiResponseContent = generateAIResponse();
      const newMsg = { role: 'assistant', content: aiResponseContent };
      setMessages(prev => [...prev, newMsg]);
      setIsTyping(false);
    }, 1500 + Math.random() * 1000); // 1.5s - 2.5s delay
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)]">
      <div className="mb-4 flex items-center gap-2">
        <h1 className="text-2xl font-bold text-white flex items-center gap-2">
          AI Insights <Sparkles className="w-5 h-5 text-indigo-400" />
        </h1>
      </div>

      <div className="flex-1 bg-gray-900 border border-gray-800 rounded-2xl shadow-xl flex flex-col overflow-hidden">
        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6">
          {messages.map((msg, index) => (
            <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              key={index} 
              className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'assistant' && (
                <div className="w-8 h-8 rounded-full bg-indigo-500/20 flex flex-shrink-0 items-center justify-center border border-indigo-500/50">
                  <Bot className="w-5 h-5 text-indigo-400" />
                </div>
              )}

              <div 
                className={`max-w-[80%] rounded-2xl px-5 py-3 ${
                  msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-tr-sm' 
                    : 'bg-gray-800 text-gray-200 border border-gray-700 rounded-tl-sm'
                }`}
                dangerouslySetInnerHTML={{
                  // Very basic markdown parsing for bold text
                  __html: msg.content.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
                }}
              />

              {msg.role === 'user' && (
                <div className="w-8 h-8 rounded-full bg-gray-700 flex flex-shrink-0 items-center justify-center border border-gray-600">
                  <User className="w-5 h-5 text-gray-300" />
                </div>
              )}
            </motion.div>
          ))}

          {isTyping && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex gap-4 justify-start">
              <div className="w-8 h-8 rounded-full bg-indigo-500/20 flex items-center justify-center border border-indigo-500/50">
                 <Bot className="w-5 h-5 text-indigo-400" />
              </div>
              <div className="bg-gray-800 border border-gray-700 rounded-2xl rounded-tl-sm px-5 py-4 flex items-center gap-1">
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
              </div>
            </motion.div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-gray-800/50 border-t border-gray-800">
          <form onSubmit={handleSend} className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about your spending habits, trends, or budget..."
