  );
}

import { useState, useMemo } from 'react';
import useFinanceStore from '../store/useFinanceStore';
import { exportToCSV, formatINR } from '../utils/helpers';
import RoleGuard from '../components/ui/RoleGuard';
import { Download, Search, Trash2, ArrowUpDown } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Transactions() {
  const { transactions, deleteTransaction } = useFinanceStore();

  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [sortOrder, setSortOrder] = useState('desc');

  const filteredData = useMemo(() => {
    let result = transactions.filter(t => 
      t.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      t.category.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (filterType !== 'all') {
      result = result.filter(t => t.type === filterType);
    }

    result.sort((a, b) => {
      const dateA = new Date(a.date).getTime();
      const dateB = new Date(b.date).getTime();
      return sortOrder === 'desc' ? dateB - dateA : dateA - dateB;
    });

    return result;
  }, [transactions, searchTerm, filterType, sortOrder]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Transactions</h1>
          <p className="text-gray-400">Manage your income and expenses</p>
        </div>

        <button 
          onClick={() => exportToCSV(filteredData, 'finflow_transactions.csv')}
          className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-white px-4 py-2 rounded-lg transition-colors border border-gray-700 shadow-sm"
        >
          <Download className="w-4 h-4" />
          Export CSV
        </button>
      </div>

      <div className="bg-gray-900 border border-gray-800 rounded-2xl p-4 sm:p-6 shadow-xl">
        {/* Controls */}
        <div className="flex flex-col md:flex-row gap-4 mb-6">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 w-5 h-5" />
            <input 
              type="text" 
              placeholder="Search by title or category..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-gray-800 border border-gray-700 text-white pl-10 pr-4 py-2.5 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            />
          </div>

          <select 
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
            className="bg-gray-800 border border-gray-700 text-white px-4 py-2.5 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer"
          >
            <option value="all">All Types</option>
            <option value="income">Income</option>
            <option value="expense">Expense</option>
          </select>

          <button 
            onClick={() => setSortOrder(prev => prev === 'desc' ? 'asc' : 'desc')}
            className="flex items-center justify-center gap-2 bg-gray-800 border border-gray-700 hover:bg-gray-700 text-white px-4 py-2.5 rounded-xl transition-colors"
          >
            <ArrowUpDown className="w-4 h-4" />
            {sortOrder === 'desc' ? 'Newest' : 'Oldest'}
          </button>
        </div>

        {/* Table */}
        <div className="overflow-x-auto rounded-xl border border-gray-800">
          <table className="w-full text-left text-sm text-gray-400">
            <thead className="bg-gray-800/50 text-gray-300 uppercase text-xs">
              <tr>
                <th className="px-6 py-4 font-medium">Date</th>
                <th className="px-6 py-4 font-medium">Title</th>
                <th className="px-6 py-4 font-medium">Category</th>
                <th className="px-6 py-4 font-medium text-right">Amount</th>
                <th className="px-6 py-4 font-medium text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800 bg-gray-900">
              {filteredData.length > 0 ? (
                filteredData.map((t, i) => (
                  <motion.tr 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                    key={t.id} 
                    className="hover:bg-gray-800/50 transition-colors"
                  >
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(t.date).toLocaleDateString('en-IN')}</td>
                    <td className="px-6 py-4 font-medium text-gray-200">{t.title}</td>
                    <td className="px-6 py-4">
                      <span className="bg-gray-800 px-3 py-1 rounded-full text-xs font-medium border border-gray-700 shadow-sm">{t.category}</span>
                    </td>
                    <td className={`px-6 py-4 text-right font-medium ${t.type === 'income' ? 'text-emerald-400' : 'text-rose-400'}`}>
                      {t.type === 'income' ? '+' : '-'}{formatINR(t.amount)}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <RoleGuard requiredRole="admin" fallbackText="Admin only">
                        <button 
                          onClick={() => deleteTransaction(t.id)}
                          className="p-2 text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 rounded-lg transition-all"
                          title="Delete Transaction"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </RoleGuard>
                    </td>
                  </motion.tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="px-6 py-8 text-center text-gray-500">
                    No transactions found matching your criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { create } from "zustand";
import { persist } from "zustand/middleware";
import mockData from "../data/mockData";

const useFinanceStore = create(
  persist(
    (set, get) => ({
      transactions: mockData,
      role: "admin",
      darkMode: true,

      setRole: (role) => set({ role }),

      toggleDarkMode: () =>
        set((state) => ({ darkMode: !state.darkMode })),

      addTransaction: (tx) =>
        set((state) => ({
          transactions: [...state.transactions, tx],
        })),

      deleteTransaction: (id) =>
        set((state) => ({
          transactions: state.transactions.filter((t) => t.id !== id),
        })),

      resetData: () => set({ transactions: mockData }),

      addToast: () => {}, // placeholder (you already handle UI)
    }),
    {
      name: "finance-storage",
    }
  )
);

export default useFinanceStore;
